// Configuration LLM
const provider = 'openai'; // 'openai', 'anthropic', 'ollama', 'mistral'
const model = 'gpt-4-turbo'; // ou 'claude-3-5-sonnet-latest', 'llama3', etc.

// Prompt - utilisez input pour accéder aux données d'entrée
const prompt = input.prompt || 'Bonjour !';

async function callLLM() {
  if (provider === 'openai') {
    const OpenAI = require('openai');
    const client = new OpenAI();
    const response = await client.chat.completions.create({
      model,
      messages: [{ role: 'user', content: prompt }],
      temperature: 0.7,
      max_tokens: 2048
    });
    return { response: response.choices[0].message.content };
  }

  if (provider === 'anthropic') {
    const Anthropic = require('@anthropic-ai/sdk');
    const client = new Anthropic();
    const response = await client.messages.create({
      model,
      max_tokens: 2048,
      messages: [{ role: 'user', content: prompt }]
    });
    return { response: response.content[0].text };
  }

  if (provider === 'ollama') {
    const res = await fetch(`${process.env.OLLAMA_HOST || 'http://localhost:11434'}/api/generate`, {
      method: 'POST',
      body: JSON.stringify({ model, prompt, stream: false })
    });
    const data = await res.json();
    return { response: data.response };
  }
}

const result = await callLLM();
console.log(JSON.stringify(result));

